// 1. Get the raw text
let rawText = $input.first().json.content.parts[0].text;

// 2. Clean the Markdown wrappers
const cleanJson = rawText.replace(/```json|```/g, "").trim();

try {
  const response = JSON.parse(cleanJson);

  // 3. Return a single object containing all prompts
  return [
    { 
      json: { 
        feature: response.image_1_feature,
        ingredients: response.image_2_ingredients,
        cooking: response.image_3_cooking,
        final: response.image_4_final_presentation
      } 
    }
  ];
} catch (error) {
  return [{ json: { error: "Failed to parse JSON", raw: rawText } }];
}

// 1. Read the binary file from n8n's disk into memory. 
// Note: 'data' is the name of your binary channel from the HTTP request.
const imageBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');

// 2. Convert that raw buffer into a Base64 text string
const base64String = imageBuffer.toString('base64');

// 3. Get the mime type (image type) directly from the binary data properties
const imageType = $input.first().binary.data.mimeType;

// 4. Attach both the Base64 string and the image type to our JSON output
return [{
  json: {
    ...$input.first().json,
    base64_image: base64String,
    mime_type: imageType
  }
}];

// Loop through all incoming items
const results = $input.all().map(item => {
  // 1. Get the 'parts' array from the Gemini response
  const parts = item.json.candidates?.[0]?.content?.parts || [];

  // 2. SEARCH for the part that contains 'inlineData' (The Image)
  // This ignores any parts that only contain 'text'
  const imagePart = parts.find(part => part.inlineData);

  if (imagePart) {
    // 3. If we found an image, return just the clean data
    return {
      json: {
        success: true,
        mime_type: imagePart.inlineData.mimeType,
        base64_image: imagePart.inlineData.data,
        // Keep the original prompt text if you need it for the filename later
        original_prompt: item.json.promp || "image" 
      }
    };
  } else {
    // Handle cases where Gemini refused to generate an image
    return {
      json: {
        success: false,
        error: "No image found in Gemini response",
        raw_response: item.json
      }
    };
  }
});

return results;

