const keys = ['feature', 'ingredients', 'cooking', 'final'];
const mergedData = {};
const items = $input.all();

// Fill whatever images exist
items.forEach((item, index) => {
  const keyName = keys[index] || `image_${index + 1}`;
  const data = item.json;
  mergedData[keyName] = {
    ...data,
    url: data.url || data?.guid?.rendered || ""
  };
});

// ✅ Default any missing image slots to empty string
keys.forEach(key => {
  if (!mergedData[key]) {
    mergedData[key] = { url: "" };
  }
});

return [{ json: mergedData }];

const categories = $input.all();

const categoriesText = categories.map(cat => {
  return `- ${cat.json.name} (ID: ${cat.json.real_cuid})`;
}).join('\n');

return [{
  json: {
    categories_text: categoriesText,
    total_categories: categories.length,
    categories_list: categories.map(c => ({
      id: c.json.real_cuid,   // ✅ Use real_cuid, NOT id
      name: c.json.name,
      slug: c.json.slug || ""
    }))
  }
}];

const blog = $('AI Blog Generator V2').first().json.output;
const extracted = $('AI Data Extractor1').first().json.output;
const picture = $('all picture').first().json;
const categoriesList = $('category').first().json.categories_list || [];

// ✅ Match AI category name to a real DB ID — never trust the AI-generated ID
const matchedCategory = categoriesList.find(cat =>
  cat.name.toLowerCase().includes(extracted.category.toLowerCase()) ||
  extracted.category.toLowerCase().includes(cat.name.toLowerCase())
);

// Fallback to first category if nothing matches
const resolvedCategoryId = matchedCategory?.id || categoriesList[0]?.id || "";

return {
  json: {
    title: blog.title,
    description: blog.meta_description,
    content: blog.article_html,
    featuredImage: picture.feature?.guid?.rendered || picture.feature?.url || "",
    categoryId: resolvedCategoryId,   // ✅ Always a real DB ID
    status: "PUBLISHED",
    tagNames: extracted.keywords || [],
    difficulty: "EASY",
    prepTime: parseInt(extracted.prep_time_minutes) || 0,
    cookTime: parseInt(extracted.cook_time_minutes) || 0,
    totalTime: parseInt(extracted.total_time_minutes) || 0,
    servings: parseInt(extracted.servings_number) || 4,
    calories: extracted.calories_number || 0,
    ingredients: extracted.ingredients.map(ing => ({
      amount: "",
      unit: "",
      name: ing
    })),
    instructions: extracted.instructions.map(step => ({
      step: step.stepNumber,
      text: step.text
    })),
    notes: extracted.notes || "",
    nutrition: {
      protein: extracted.protein || "",
      carbs: extracted.carbs || "",
      fat: extracted.fat || ""
    },
    seo: {
      metaTitle: blog.title,
      metaDescription: blog.meta_description,
      focusKeyword: blog.focus_keyword,
      keywords: extracted.keywords || [],
      schemaEnabled: true
    }
  }
};

