  json: {
    ...$input.first().json,
    base64_image: base64String,
    mime_type: imageType
  }
}];

// 1. Loop through items
const results = [];
for (const item of $input.all()) {
  const parts = item.json.candidates?.[0]?.content?.parts || [];
  const imagePart = parts.find(part => part.inlineData);

  if (imagePart) {
    // 2. Convert Base64 to Binary Buffer
    const imageBuffer = Buffer.from(imagePart.inlineData.data, 'base64');

    // 3. Prepare Binary Data for Upload
    const binaryData = await this.helpers.prepareBinaryData(
      imageBuffer,
      'generated_pin.png',
      imagePart.inlineData.mimeType
    );

    results.push({
      json: {
        success: true,
        original_prompt: item.json.prompt || "image"
      },
      binary: {
        data: binaryData
      }
    });
  }
}
return results;

// Get all incoming items (the rows)
const allBoards = $input.all().map(item => item.json);

// Return them as a single stringified JSON list so the AI can read it easily
return {
  json: {
    // We create a clean string list like: "Name: ID"
    available_boards_string: allBoards.map(b => `Board Name: "${b['bord name']}", ID: ${b['bord id']}`).join('\n'),
    // We also keep the raw array just in case
    available_boards_array: allBoards
  }
};

