const output = $input.first().json.output?.trim().toUpperCase();
const isValid = output === 'TRUE';

return [{
  json: {
    ...($input.first().json),
    is_valid_recipe: isValid,
    validation_result: isValid ? 'TRUE' : 'FALSE'
  }
}];

// Get the list of posts from the previous node
const posts = $input.all();

// Create a simple text list of titles and links
const linksList = posts.map(post => {
  return `- ${post.json.title.rendered}: ${post.json.link}`;
}).join('\n');

// Return it as a single field "existing_posts_list"
return [{
  json: {
    existing_posts_list: linksList,
    total_posts: posts.length
  }
}];
